module top_module(
  output reg dataout,
  input clock,
  input reset,
  input datain
);// define the states
  parameter S0 = 2'b00; // initial X_state
  parameter S1 = 2'b01; // X_state after first 1
  parameter S2 = 2'b10; // X_state after second 1
  parameter S3 = 2'b11; // X_state after third 1

  // define the X_state register and next X_state logic
  reg [1:0] X_state, next_state;
  always @ (posedge clock, posedge reset)
  begin
    if (reset)
      X_state <= S0;
    else
      X_state <= next_state;
  end

  // define the output logic
  always @ (X_state, datain)
  begin
    case (X_state)
      S0: dataout <= 0;
      S1: dataout <= 0;
      S2: dataout <= 0;
      S3: dataout <= 1;
      default: dataout <= 0;
    endcase
  end

  // define the next X_state logic
  always @ (X_state, datain)
  begin
    case (X_state)
      S0: if (datain) next_state <= S1; else next_state <= S0;
      S1: if (datain) next_state <= S2; else next_state <= S0;
      S2: if (datain) next_state <= S3; else next_state <= S0;
      S3: if (datain) next_state <= S3; else next_state <= S0;
      default: next_state <= S0;
    endcase
  end

endmodule
